                  <span style={{ fontSize: '0.85rem', color: 'var(--color-text-muted)' }}>/ 100</span>
                </div>
              </div>
            </div>

            {/* Visual Charts */}
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(400px, 1fr))', gap: '24px' }}>
