                      <XAxis dataKey="name" stroke="var(--color-text-muted)" />
                      <YAxis stroke="var(--color-text-muted)" />
                      <Tooltip contentStyle={{ background: 'var(--bg-main)', border: '1px solid var(--border-color)' }} />
                      <Bar dataKey="amount">
